;◆イベント◆

; 初期発生イベント
events = [1, 2]

;-------------------------------------------------------------------------------
*event_1
;[exp] true

@se f=erase
@eval exp='game.map.getFloorInfo().img = void'
@eval exp='game.updateView()'
@notice text="The floor vanished!"
@eval exp='game.map.getFloorInfo().img = "wood"'
@changefloor icon=66 info=消滅する床
@eval exp='game.fallToLowerFloor(%[map: game.map.lower])'

[eventoff]
